def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity == 0:
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.2:
            for x in range(1, 6):
                score += (np.cos(ratio * np.pi * x) ** 2) * x * 3
            score -= np.tanh(ratio * 5) * 10
        elif 0.2 <= ratio < 0.5:
            base = ratio ** 2 * 25
            score += base
            for k in range(1, int(capacity) + 1):
                if capacity % k == 0 and k < item:
                    score += (k / (1 + ratio)) * 0.2
            if int(capacity) % 4 == 0:
                score += np.sqrt(capacity) / (1 + ratio * 2)
        elif 0.5 <= ratio <= 0.85:
            for a in range(1, 4):
                val = (ratio ** a) * (np.sin(a * np.pi * ratio) + np.cos(a * np.pi / 2)) * 7
                score += val
            if capacity > 10:
                for b in range(2, min(10, int(capacity))):
                    if capacity % b == 0 and b != 1:
                        score -= np.log1p(b) * 1.5
            score += (np.exp(-ratio) * 12)
        elif 0.85 < ratio <= 1.0:
            score += 50 / (1 + np.exp(-30 * (ratio - 0.9)))
            for c in range(1, 5):
                partial = ((ratio * c) % 1) ** 2 * 4
                score += partial
            if capacity % 7 == 0:
                score *= 1.15
        else:
            int_ratio = int(np.floor(ratio))
            frac_ratio = ratio - int_ratio
            penalty = 0
            for d in range(1, int_ratio + 2):
                if d != 0 and int_ratio % d == 0:
                    penalty += (d ** 1.5) / (1 + frac_ratio)
            for e in range(1, 6):
                penalty += ((frac_ratio * e) % 1) * 2.5
            score = penalty + (ratio - 1) * 30
            if ratio > 3:
                for f in range(1, int(capacity // 3) + 1):
                    if capacity % f == 0:
                        score += np.log1p(f * ratio) * 0.7
            if capacity % 2 == 0 and ratio > 1.2:
                score *= 1.2
            if capacity > 50:
                score += np.sqrt(capacity) * 0.4
        if (int(capacity) % 6 == 0 and ratio < 0.8) or (capacity < 5 and ratio > 1):
            score *= 1.05
        priorities[i] = score
    min_priority = np.min(priorities[np.isfinite(priorities)])
    priorities = np.where(np.isfinite(priorities), priorities, min_priority + 250)
    return priorities
